var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"빠르고! 강하게!","JPN":"速く！　強く！","ENG":"Fast and strong!","TWN":"快又強！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"적을 섬멸한다────!!","JPN":"敵を殲滅する────！！","ENG":"Annihilate the enemy────!!","TWN":"殲滅敵人────！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위─── 수리 불───가.</color>","JPN":"<color=#ff3636>損傷部位───修理不───可。</color>","ENG":"<color=#ff3636>Damage sustained─── repairs impos───sible.</color>","TWN":"<color=#ff3636>損壞部位───無法───維修。</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC"},{"id":"L8_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>시스템─── 다운──.</color>","JPN":"<color=#ff3636>システム───ダウン。</color>","ENG":"<color=#ff3636>System─── down──.</color>","TWN":"<color=#ff3636>系統─── 停機──</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_DAMAGE_DIE_02"},{"id":"L10_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"이 몸! 약자를 수호하고 정의를 관철하는 방랑 기사!","JPN":"この私が弱者を守り、正義を貫く放浪の騎士！","ENG":"I am the wandering knight who shields the weak and upholds justice!","TWN":"本小姐！扶持弱者貫徹正義的流浪騎士！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"오늘도, 정의 실현───!","JPN":"今日も、正義実現───！","ENG":"Once more, justice prevails───!","TWN":"今天也要實現正義───！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"우오오…! 혼자서 대 침식 4종 섬멸 병기를 쓰러트릴 줄이야……!","JPN":"うおお……！　一人で対侵食第4種殲滅兵器を倒すだなんて……！","ENG":"Whoa...! Took down an Anti-Corruption Category 4 Weapon all on your own...!","TWN":"哇喔…！竟然獨自打倒殲滅侵蝕4類兵器……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"굉장한데? 과연 쌤이 선별한 <color=#ffd34c>특기전력</color>이라고 할만하다.","JPN":"すごいやん。さすが先生が選別した<color=#ffd34c>特記戦力</color>いうだけのことはあるな。","ENG":"Impressive. No wonder Teach picked you as a <color=#ffd34c>Special Operations Asset</color>.","TWN":"厲害喔？果然不愧是老師挑選的<color=#ffd34c>特殊戰力</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하지만 저 가면… 어쩌면…….","JPN":"でもあの仮面……もしかすると……","ENG":"But that mask... maybe...","TWN":"但那個面具……說不定……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff* *Huff* *Huff...!*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 니 괘안나, 호흡이 좀 가쁜 것 같은데?","JPN":"あんた大丈夫か？　呼吸が乱れとるやないか。","ENG":"Hey, you all right? You look winded.","TWN":"喂，你還好嗎？感覺你呼吸有點急促。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아, 괜찮아요. 오러화를 하고 난 뒤에는 살짝 지쳐서요.","JPN":"あ、大丈夫です。オーラ化した後は少し疲れてしまうので。","ENG":"Ah, I'm fine. Just a little exhausted after using Aurafication.","TWN":"嗯，沒關係。進行奧蘿化之後有點疲憊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아무래도 아직 수련이 부족한 탓이겠죠.","JPN":"まだ修行が足りないんでしょうね。","ENG":"I guess I still need more training.","TWN":"看來還是因為我的修煉不夠吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"음, 그 정도로 카운터 능력을 끌어올려준다 카면, 확실히 보통 물건은 아닌 것 같다.","JPN":"うーん、それほどカウンター能力を引き上げてくれるなんて、絶対普通の代物じゃない。","ENG":"Mm, if it can boost your Counter ability that much, it's definitely no ordinary mask.","TWN":"嗯，如果能將制裁者的能力提升到那種程度，確實不是普通的角色。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"로빈 양? 혹시 그 가면, 내 한 번 봐도 되겠나?","JPN":"ロビン、その仮面ちょっと見せてくれへん？","ENG":"Robin? Mind if I take a closer look at that mask?","TWN":"蘿蘋？那個面具，能借我看一下嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네? 오러 선생님을요?","JPN":"え？　オーラ先生をですか？","ENG":"Huh? You mean Ms. Aura?","TWN":"嗯？是要看奧蘿師父嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 내도 트레저 헌터다. 아티팩트 감정은 기본 중에 기본이지!","JPN":"ウチもトレジャーハンターや。アーティファクトの鑑定は基本中の基本！","ENG":"Hey, I'm a treasure hunter too. Appraising Artifacts is basic stuff!","TWN":"哈，我也是個尋寶獵人。鑒定人造神器是基本功夫！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그건 상관없지만…….","JPN":"それは構いませんが……","ENG":"I mean, I guess that's fine, but...","TWN":"可以是可以……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"흐흐흐흐…….","JPN":"ふふふふ………","ENG":"He he he he...!","TWN":"呵呵呵呵……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미, 미리네 씨?","JPN":"マ、マリさん？","ENG":"M-Ms. Mi Rinae?","TWN":"宓，宓璃奈？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"로빈 양, 내 짧은 인생에서 배운 게 있다 아이가.","JPN":"ロビン。ウチはさ、この短い人生の中で学んだことがあんねん。","ENG":"Robin, if there's one thing life's taught me...","TWN":"蘿蘋，我在短暫的人生中學到一些東西。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"인간이란 계략을 꾸미면 꾸밀수록, 예기치 못한 사태로 계략이 와르르 무너지는기다.","JPN":"人間は計略を弄すれば弄するほど、予期せぬ事態で計略がくずれさるんや。","ENG":"It's that the more schemes humans plot, the easier they crumble to unforeseen events.","TWN":"就是人類的計畫永遠趕不上變化。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그라믄 어쩌겠노? 인간을 뛰어넘는 존재가 되야쓰겠지?","JPN":"じゃあどないする？　人間を超える存在になるしかないやろ？","ENG":"So what's the answer? You've got to go beyond being human!","TWN":"那該怎麼辦呢？當然必須成為超越人類的存在囉？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"무슨 말을 하시는 거예요, 미리네 씨?","JPN":"何を言っているんですか、マリさん？","ENG":"What are you talking about, Ms. Mi Rinae?","TWN":"你在說什麼呢，宓璃奈？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"나는 인간을 그만두겠다, 로빈!! 나는 인간을 초월할 테다!!","JPN":"ウチは人間をやめるで、ロビン！！　ウチは人間を超越するッ！！","ENG":"I renounce my humanity, Robin!! I will transcend mankind!!","TWN":"我決定不當人類了！蘿蘋！！我要超越人類！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"앗, 미리네 씨가… 오러 선생님을……?","JPN":"あっ、マリさんが……オーラ先生を……？","ENG":"W-wait, Ms. Mi Rinae...! You're putting on Ms. Aura...?","TWN":"宓璃奈……把奧蘿師父……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"으갸아아아아아아아아아아아아악───!!","JPN":"うぎゃあああああああああああっ───！！","ENG":"UWAAAAAAAHHHH────!!","TWN":"呃啊啊啊啊啊啊啊啊啊啊啊啊啊───！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_05"},{"id":"L42_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아앗, 죄송해요. 미리네 씨!","JPN":"あっ、ごめんなさい、マリさん！","ENG":"Ahh, I'm sorry! Ms. Mi Rinae!","TWN":"對，對不起，宓璃奈！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"오러 선생님은 저 말고, 다른 사람이 자길 쓰는 걸 싫어하시거든요……!","JPN":"オーラ先生は私以外の人が先生を被るのを嫌がるんです……！","ENG":"Ms. Aura doesn't like anyone but me wearing her...!","TWN":"奧蘿師父只能給我用，其他人師父都討厭……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마! 그런 건… 미리미리 말 좀 해주지 그랬노오오……!!","JPN":"こら！　そんなことは……先に言うてやぁぁぁ……！！","ENG":"C'mon! You could've told me that a little sooner...!","TWN":"喂！這種事……你要早點告訴我啊啊啊……！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"자, 그럼 슬슬 움직입시다.","JPN":"さて、そろそろ動くで。","ENG":"All right, let's get moving.","TWN":"好，那我們開始行動唄。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"섬이 그리 크지는 않지만, 칸 영감을 찾으려면 서둘러야……","JPN":"そんなに広い島じゃないけど、カンのじじいを探すなら急がへんと……","ENG":"The island's not that big, but if we want to find old man Khan, we'd better hurry...","TWN":"島雖然不大，但要找坎老頭的話，得抓緊時間……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"……저.","JPN":"……私。","ENG":"...I.","TWN":"……我。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"저, 할아버지를 가장 빨리 찾을 수 있는 방법을 알고 있어요.","JPN":"私、おじいさまを早く見つけ出せる方法を知っています。","ENG":"\\"I know the fastest way to find Grandfather.\\"","TWN":"我知道一個能夠最快地找到爺爺的方法。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……라고 시타 아가씨께서 한 가지 제안하십니다.","JPN":"……と、シータお嬢様がご提案されています。","ENG":"...is what Lady Sita says offering a suggestion.","TWN":"……悉多小姐說有一個建議。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"방법이라고예?","JPN":"方法？","ENG":"A suggestion, huh?","TWN":"方法？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"……할아버지는.","JPN":"……おじいさまは。","ENG":"...Grandfather...","TWN":"……爺爺。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"할아버지는 평생을 바쳐 황금향의 유산을 찾으셨고.","JPN":"おじいさまは生涯を黄金郷の遺産探しに捧げていて。","ENG":"\\"Grandfather spent his entire life seeking the legacy of the Golden Vale.\\"","TWN":"爺爺一生都在尋找黃金城的寶藏。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"최근에는 그 단서들을 조합하여, 장소를 거의 확정하셨죠.","JPN":"最近では今までの手がかりを組み合わせて場所をほぼ特定していたんです。","ENG":"\\"And recently, he nearly confirmed its location by piecing together the clues.\\"","TWN":"最近透過組合那些線索，幾乎已經確定黃金城的所在地。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그곳이 여기, 태양이 떠오르는 천공섬이에요.","JPN":"それがここ、太陽が昇る天空島です。","ENG":"\\"That place is here. The Dawnbreak Floating Island.\\"","TWN":"就是這裡，日出東方天空島。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……라고 시타 아가씨께서는 확신에 차 말씀하십니다.","JPN":"……と、シータお嬢様が確信に満ちておっしゃっています。","ENG":"...is what Lady Sita says with conviction.","TWN":"……悉多小姐滿懷信心地說道。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그라믄 그 단서들을 잘 맞춰보면, 영감님을 찾을 수 있다는 소리네예?","JPN":"てことは、その手がかりを上手く辿っていけば、じじいが見つかるってことやな？","ENG":"So if we follow those clues, we'll be able to track the old man down?","TWN":"意思是如果把那些線索好好拼湊起來，就能找到坎老頭是吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"저도…….","JPN":"私も……","ENG":"I also...","TWN":"我……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_PRIDE"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"저도 할아버지께 도움이 되기 위해, <color=#ffd34c>이면세계 고고학</color>을 공부해 왔어요.","JPN":"私もおじいさまの役に立ちたくて、<color=#ffd34c>裏世界考古学</color>を勉強してきました。","ENG":"\\"I also studied <color=#ffd34c>Counterside Archaeology</color> to aid Grandfather.\\"","TWN":"我為了幫助爺爺，一直在學習<color=#ffd34c>異界考古學</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_PRIDE"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그리고 황금향의 전설과 그 단서들을 전부 알고 있죠.","JPN":"そして黄金郷の伝説とその手がかりを、すべて知っています。","ENG":"\\"And I know every legend and clue about the Golden Vale.\\"","TWN":"而且我知道所有有關黃金城的傳說和線索。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_PRIDE"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……라고 시타 아가씨께서는 콧대가 높아져 자신만만하십니다.","JPN":"……と、シータお嬢様は鼻高々におっしゃっています。","ENG":"...is what Lady Sita says boasting with pride.","TWN":"……悉多小姐鼻孔朝天，自信滿滿地說道。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_PRIDE"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"……흥!","JPN":"……ふん！","ENG":"...Hmph!","TWN":"……哼！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_HATE"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"아, 콧대가 높아졌다는 표현은 제 실수였군요. 정정하겠습니다.","JPN":"あ、鼻高々にという表現は私の失言でした。そこは訂正します。","ENG":"Ah, sorry. That \\"boasting\\" part was my mistake. Allow me to rephrase.","TWN":"糟糕，說小姐鼻孔朝天是我的錯，我會更正的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_HATE"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"잠깐, 이면세계 고고학이라고요?","JPN":"裏世界考古学、ですか？","ENG":"Hold on. Counterside Archaeology?","TWN":"等一下，你是說異界考古學？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이면세계에 남아있는 유적과 유물을 통해, 그 세계의 문명을 짐작해보는 학문이다.","JPN":"裏世界に残っている遺跡と遺物を通して、その世界の文明を推測する学問や。","ENG":"It's the study of ruins and relics left in the Counterside, to guess at their civilizations.","TWN":"是透過異界遺留下來的遺跡和聖物，推測那個世界文明的學問。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아티팩트가 어디서 왔는지 알면, 거기에 담긴 기술이나 신비를 분석할 수 있거든.","JPN":"アーティファクトがどこから来たのかが分かれば、そこに宿る技術や神秘を分析できる。","ENG":"If you know where an Artifact came from, you can analyze the technology or mysteries within it.","TWN":"如果知道人造神器的來源，就可以分析其中的技術或神秘之處。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하지만 황금향의 전설은…….","JPN":"せやけど、黄金郷の伝説は……","ENG":"But the Golden Vale's legend...","TWN":"但是黃金城的傳說是……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"찬란하게…….","JPN":"燦々と……","ENG":"When the radiant sun...","TWN":"當耀眼……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"찬란하게 빛나는 태양이 나무뿌리에 가려, 그 빛을 잃어버리게 될 때.","JPN":"燦々と輝く太陽が木の根に隠れ、その光を失う時。","ENG":"\\"When the radiant sun is veiled by roots, its light fading away...\\"","TWN":"當璀璨耀眼的陽光被樹根遮蔽而失去光芒之時，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"하늘이 갈라지며 땅과 구름이 맞닿는 곳, 어딘가 황금의 도시가 모습을 드러내고.","JPN":"天が切り裂かれ、地と雲が交わる場所、そのどこかに黄金の都市が姿を現し、","ENG":"\\"The heavens will split open, and where earth and cloud meet, a golden city will appear.\\"","TWN":"天空將會裂開，在大地與雲彩交會的地方，黃金城將現身。  "},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그곳, 황금향이 남긴 유산이 수많은 이들을 구하게 되리라.","JPN":"かの地、黄金郷が残した遺産が多くの者を救うであろう。","ENG":"\\"There, the Golden Vale's Legacy will save countless lives.\\"","TWN":"黃金城留下的寶藏，將拯救無數的人。  "},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"할아버지께서는…….","JPN":"おじいさまは……","ENG":"Grandfather said...","TWN":"爺爺曾說過……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"할아버지께서는 황금향에 다다르기 위해서는.","JPN":"おじいさまは、黄金郷にたどり着くためには……","ENG":"Grandfather said, to reach the Golden Vale...","TWN":"要去黃金城的話，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"<color=#ffd34c>출처가 같은 아티팩트</color>가 필요하다고 하셨어요.","JPN":"<color=#ffd34c>出処が同じアーティファクト</color>が必要だと言っていました。","ENG":"\\"<color=#ffd34c>Artifacts of shared origin</color> are required.\\"","TWN":"<color=#ffd34c>需要同來源的人造神器</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"지금까지 같은 세계의 물건으로 밝혀진 아티팩트는 세 가지…….","JPN":"今まで、同じ世界から来たものだと判明したアーティファクトは3つ……","ENG":"\\"So far, only three have been identified as from the same world...\\"","TWN":"到目前為止，被確認是同一世界物品的人造神器有三種……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"그리고 우리는…….","JPN":"そして私たちは……","ENG":"And you can say...","TWN":"而我們……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그리고 우리는 이미 그 중 한 가지 아티팩트를 손에 넣었다고 할 수 있어요.","JPN":"そして私たちは、すでにそのうちの1つを手に入れました。","ENG":"\\"And you can say that we already possess one of them.\\"","TWN":"而我們已經拿到其中一件。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"네? 이미 손에 넣었다고예?","JPN":"え？　もう手に入ってる？","ENG":"Huh? Already have one?","TWN":"什麼？已經到手了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그렇습니다.","JPN":"はい。","ENG":"That's right.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"첫 번째는 <color=#ffd34c>검은 숲을 수호하는 거미의 눈알</color>…….","JPN":"1つ目は<color=#ffd34c>黒い森を守護するクモの目玉</color>……","ENG":"The first is the <color=#ffd34c>eye of the Black Forest Guardian Spider</color>...","TWN":"第一件是<color=#ffd34c>守護黑森林的蜘蛛之眼</color>……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"거미의 눈알이라고……?","JPN":"クモの目玉……？","ENG":"A spider's eye...?","TWN":"蜘蛛之眼……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하, 그렇네! 모더레이터……!","JPN":"なるほど、モデレーターか……！","ENG":"Aha, of course! The Moderator...!","TWN":"啊哈，沒錯！仲裁者……！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"모더레이터는 구관리국에서 만들었지만, 환경에 따라 알고리즘이 바꿔뿌는 놈이제!","JPN":"モデレーターは旧管理局で作られたけど、環境によってアルゴリズムが変わるやつやな！","ENG":"It may have been built by the Old Administration, but its algorithms shift with the environment!","TWN":"仲裁者是舊管理局製造的，卻是一個可以根據環境改變演算法的傢伙呢！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"특정 이면세계 환경에 오래 노출되었다면, 그 특성이 변할 수도 있는 기다!","JPN":"特定の裏世界の環境に長時間露出していれば、その特性も変わることがある！","ENG":"If it's been exposed long enough to a particular Counterside, its traits could change!","TWN":"如果長時間暴露在特定的異界環境中，其特性可能會發生變化！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"근데 그래도…… 근거가 좀 약하지 않나예?","JPN":"でも……これだけやと根拠が弱ないんか？","ENG":"Still... isn't that kind of flimsy as proof?","TWN":"不過就算是這樣……證據是不是有點不足呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이론상으론, 모더레이터는 차원 이동을 통해, 어디든 나타날 수 있지 않습니까?","JPN":"理論上だと、モデレーターは次元移動でどこにでも現れるんやろ？","ENG":"Theoretically, Moderators can warp in anywhere, can't they?","TWN":"理論上，仲裁者可以透過次元移動，出現在任何地方，不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"이 일대에서…….","JPN":"この一帯に……","ENG":"In this region...","TWN":"這一帶……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"이 일대에서 출몰하는 모더레이터는 이끼로 뒤덮인 프레임을 가졌거든요.","JPN":"この一帯に出没するモデレーターは、苔に覆われたフレームを持っているんです。","ENG":"\\"In this region, the Moderators all have moss-covered frames.\\"","TWN":"這一帶出沒的仲裁者，外殼上覆滿了苔蘚。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그러고 보니…….","JPN":"そういえば……","ENG":"Come to think of it...","TWN":"這麼說來……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"이 모더레이터, 몸체에 이끼가 잔뜩 끼어있어요.","JPN":"このモデレーター、胴体に苔がいっぱい生えています。","ENG":"This Moderator's chassis is covered in moss too.","TWN":"這個仲裁者，身體上長滿了苔蘚。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"네. 그리고 그 이끼는…….","JPN":"はい。そしてその苔は……","ENG":"Yes. And that moss...","TWN":"是的。而且那個苔蘚……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"시, 시타 님? 지금 뭐하시는깁니까!?","JPN":"シ、シータさん？　何しとる？","ENG":"L-Lady Sita! What are you doing?!","TWN":"悉，悉多？你在做什麼！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"고레벨 침식지대에서는, 작은 상처 하나도 진짜 위험하다 아닙니까!","JPN":"高レベルの侵食地帯では、小さな傷でも危ないんやで！","ENG":"In a high-level Corrupted Area, even a scratch can be deadly!","TWN":"在高等級侵蝕地帶，即使是小傷口也可能很危險！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"백문불여일견… 보여드리고 싶었거든요…….","JPN":"百聞は一見にしかず……お見せしたかったので……","ENG":"Seeing is believing... I wanted to show you...","TWN":"百聞不如一見……我想讓你們親眼看看……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"사람의… 피가 닿으면…….","JPN":"人の……血に触れると……","ENG":"The trait of Golden Vale moss... and how it turns golden...","TWN":"如果碰到人的……血……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"금빛으로 변하는… 황금향 이끼의 특성을요…….","JPN":"金色に変わる……黄金郷の苔の特性を……","ENG":"When human blood... touches it...","TWN":"會變成金色……這就是黃金城苔蘚的特性……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};